import{_ as t,o as a,c as r,a3 as s}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"Setting Up AI Providers","description":"Configure AI settings, API keys, local endpoints, and feature flags.","frontmatter":{"title":"Setting Up AI Providers","description":"Configure AI settings, API keys, local endpoints, and feature flags.","keywords":"AI settings, API key, Ollama, OpenAI, HuggingFace token, embeddings","category":"AI"},"headers":[],"relativePath":"ai/setup.md","filePath":"ai/setup.md","lastUpdated":1784354374000}'),o={name:"ai/setup.md"};function n(i,e,l,d,g,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="ai-setup" tabindex="-1">AI Setup <a class="header-anchor" href="#ai-setup" aria-label="Permalink to &quot;AI Setup&quot;">​</a></h1><p>Configure models and API settings in the <strong>AI → AI Settings</strong> menu.</p><h2 id="_1-provider-setup" tabindex="-1">1. Provider Setup <a class="header-anchor" href="#_1-provider-setup" aria-label="Permalink to &quot;1. Provider Setup&quot;">​</a></h2><p>Configure separate models for text generation and semantic features:</p><ul><li><strong>Text Provider</strong>: Generates chat responses and executes text rewrites. Supports Local API Endpoints (e.g. Ollama, LM Studio) and OpenAI.</li><li><strong>Embeddings Provider</strong>: Generates vector representations of your notes for meaning-based search. Supported via HuggingFace token configurations.</li><li><strong>Connection Test</strong>: Click <strong>Test</strong> next to either service to verify authentication and connection parameters.</li></ul><hr><h2 id="_2-feature-toggles" tabindex="-1">2. Feature Toggles <a class="header-anchor" href="#_2-feature-toggles" aria-label="Permalink to &quot;2. Feature Toggles&quot;">​</a></h2><ul><li><strong>Learn User Patterns</strong>: Allows the system to capture local usage context to improve suggestions.</li><li><strong>Generate Embeddings</strong>: Builds a local vector database of note contents for search.</li><li><strong>Discover Relationships</strong>: Analyzes references to map semantic proximity in the workspace graph.</li></ul><hr><h2 id="_3-advanced-parameters" tabindex="-1">3. Advanced Parameters <a class="header-anchor" href="#_3-advanced-parameters" aria-label="Permalink to &quot;3. Advanced Parameters&quot;">​</a></h2><p>Fine-tune AI responses:</p><ul><li><strong>Temperature</strong>: Controls creativity. Lower values yield structured, predictable output; higher values yield creative variations.</li><li><strong>Max Tokens</strong>: Bounds response length to manage speed and resource consumption.</li><li><strong>Local Storage Path</strong>: Shows where cache data is saved, with a button to <strong>Clear Learned Data</strong>.</li></ul>',12)])])}const h=t(o,[["render",n]]);export{p as __pageData,h as default};
